"""
mkt-original: Job chapters 5–7
Eliphaz's conclusion (ch5), Job's reply — wadi-friends and forensic challenge (ch6),
Job's military-service soliloquy and Psalm 8 inversion (ch7).
78 verses total: ch5 (27), ch6 (30), ch7 (21).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB_ORIGINAL_5_7 = {
  "5": {
    "1": "<p><strong>qərāʾ nāʾ hayēš ʿōnekā wəʾel mî miqqəḏōšîm tippāneh</strong>: 'Call now; is there anyone who will answer you? To which of the holy ones will you turn?' Eliphaz's rhetorical question deploys the divine council motif: the <em>qəḏōšîm</em> (holy ones) are the heavenly beings who surround YHWH's throne (Ps 89:5, 7; Zech 14:5). His point is that Job has no one in the divine court to intercede for him — a bitter irony since the reader knows Job's case has already been argued before YHWH's council in the prologue. The rhetorical device silences complaint by claiming the heavenly court is closed to the sufferer. Job's longing for an arbiter (9:33) is the direct counterpoint to this dismissal.</p>",
    "2": "<p><strong>kî-ləʾəwîl yaharōg-kaʿaś ûpōṯeh tāmîṯ qinʾāh</strong>: 'For vexation kills the fool, and jealousy slays the simple.' Eliphaz here introduces his retribution framework: emotional excess (<em>kaʿaś</em>, vexation/anger, and <em>qinʾāh</em>, jealousy/zeal) is the mark of the <em>ʾěwîl</em> (the fool who lacks moral discernment). The grammatical subject of the killing is the emotions themselves — vexation is self-destructive. This functions as a veiled accusation: Job's bitter complaint in ch3 is evidence of the very fool-anger that brings ruin. The lexical pair <em>ʾěwîl / pōṯeh</em> (fool / simple) appears together in Proverbs (e.g., Prov 7:7; 22:3) as the two grades of moral deficiency.</p>",
    "3": "<p><strong>ʾănî-rāʾîṯî ʾěwîl mašrîš wayyiqqōḇ nāwêhû pîṯʾōm</strong>: 'I have seen the fool taking root, but suddenly I cursed his dwelling.' The verb <em>mašrîš</em> (taking root, hiphil of <em>šāraš</em>) depicts the apparent stability of the wicked — a Psalm-like image of the wicked flourishing temporarily (cf. Ps 37:35). But <em>pîṯʾōm</em> (suddenly) marks the reversal: the dwelling (<em>nāweh</em>) is cursed. Eliphaz presents this as personal experience (<em>ʾănî rāʾîṯî</em>, I myself have seen), grounding retribution theology in empirical observation rather than divine revelation. Job's speeches will contest precisely this claim to empirical adequacy.</p>",
    "4": "<p><strong>yirḥăqû bānāyw mîyešaʿ wəyiddakkəʾû ḇaššaʿar wəʾên maṣṣîl</strong>: 'His children are far from safety, crushed in the gate, with none to deliver.' The <em>shaʿar</em> (gate) was the site of legal proceedings in ancient Israel: the gate community could vindicate or condemn. To be <em>dāḵaʾ</em> (crushed, beaten down) in the gate is to be legally destroyed without advocate. This resonates brutally with Job's situation: his own children died (1:18-19), and no one interceded. Yet Eliphaz is applying it to the progeny of a hypothetical <em>ʾěwîl</em> — the audience (and reader) cannot miss the implication that Job's children died because of their father's sin. This is precisely the retributive calculus YHWH will condemn in 42:7.</p>",
    "5": "<p><strong>ʾăšer qəṣîrô rāʿēḇ yōʾḵēl wəʾel-miṣṣinnîm yiqqāḥēhû wəšāʾap̄ ṣammîm ḥêlām</strong>: 'The hungry eat his harvest, even from behind thorns, and the thirsty pant after his wealth.' The verse depicts the complete unraveling of the wicked man's household economy — harvest, property, and water all stripped away by predators. The phrase <em>miṣṣinnîm</em> (from behind thorns/a thorn-hedge) suggests even his protective hedgerow is breached. The term <em>ṣammîm</em> is rare and disputed (some translate 'thirsty ones,' others 'snares'); the sense of comprehensive plunder is clear. This economic imagery for divine judgment is conventional in wisdom literature (Prov 13:22; 28:8).</p>",
    "6": "<p><strong>kî lōʾ-yēṣēʾ meʿāp̄ār ʾāwen wûmēʾăḏāmāh lōʾ-yiṣmaḥ ʿāmāl</strong>: 'For affliction does not come from the dust, nor does trouble sprout from the ground.' Eliphaz makes a causal claim: suffering (<em>ʾāwen</em>, trouble/wickedness, and <em>ʿāmāl</em>, toil/misery) is not a random natural phenomenon like weeds springing from the ground. The verse prepares for v.7's counter-assertion. The implicit syllogism: suffering has a cause → causes are moral → therefore suffering implies sin. The verse is theologically sophisticated but logically flawed in Job's case: it confuses 'suffering has a cause' with 'the cause is always the sufferer's sin.'</p>",
    "7": "<p><strong>kî-ʾāḏām leyāʾmāl yûllāḏ ûḇənê-rešep̄ yagbîhû ʿûp̄</strong>: 'For man is born to trouble as the <em>bənê-rešep̄</em> fly upward.' The phrase <em>bənê-rešep̄</em> (sons of Resheph) is one of Job's most contested idioms. Resheph was the Canaanite deity of plague and fire (cf. Ps 78:48 where <em>rešep̄</em> = bolts of fire/lightning). <em>Bənê-rešep̄</em> thus means either 'sparks' (the visual image of sparks flying upward from a fire) or 'birds of prey' (some ancient versions). The majority view is sparks: just as fire inevitably produces sparks that fly upward, man inevitably produces trouble (<em>ʿāmāl</em>). The verse supports Eliphaz's retribution logic: trouble is as natural a product of human existence as sparks from fire — implying Job's situation is simply the universal lot made visible. Eliphaz intends this as comfort, but Job experiences it as cold.</p>",
    "8": "<p><strong>ʾûlām ʾănî ʾeḏrōš ʾel-ʾēl wəʾel-ʾělōhîm ʾāśîm diḇrāṯî</strong>: 'As for me, I would seek God, and to God I would commit my cause.' Eliphaz now pivots to positive exhortation: the solution to Job's situation is not complaint but petition. The verb <em>dāraš</em> (seek, inquire) has cultic overtones in the OT (seeking YHWH at his sanctuary, consulting an oracle). <em>ʾĒl</em> and <em>ʾělōhîm</em> are used in parallelism here, as they often are in Job (the divine names throughout Job's poetic sections reflect its international/wisdom setting rather than the covenant YHWH-name). The irony: Job is doing exactly what Eliphaz prescribes (seeking God with his complaint), but Eliphaz cannot recognize Job's lament as legitimate petition.</p>",
    "9": "<p><strong>ʿōśeh gəḏōlōṯ wəʾên ḥēqer nip̄lāʾōṯ ʿaḏ-ʾên mispar</strong>: 'who does great things and unsearchable, marvelous things without number.' The hymnic participles <em>ʿōśeh... nip̄lāʾōṯ</em> (doing great things... marvelous things) open a doxological section (vv.9-16) that celebrates God's sovereign control of creation and history. <em>Nip̄lāʾōṯ</em> (wonders, marvelous deeds) is the standard vocabulary for divine salvific actions in the Psalms (e.g., Ps 9:1; 26:7; 40:5). The participial construction identifies who God is by what he continuously does. The same vocabulary will appear in YHWH's whirlwind speech (38-41), where creation's incomprehensibility vindicates divine wisdom over human theodicy.</p>",
    "10": "<p><strong>hannōṯēn māṭār ʿal-pənê-ʾāreṣ wəšōlēaḥ mayim ʿal-pənê ḥûṣôṯ</strong>: 'who gives rain on the earth and sends waters on the fields.' The participle chain continues: God's providential supply of rain is cited as evidence of his great deeds. In ancient Near Eastern thought, rain was the prerogative of the storm deity (Baal, in Canaanite religion); here it is attributed to <em>ʾĒl</em>/<em>ʾělōhîm</em>. This verse functions as a polemic: the God who controls rain is the God who controls all life — the same God who controls Job's circumstances. Eliphaz's intent is consolatory (this great God can restore you), but the verse also sets up YHWH's own interrogation of Job: 'Can you send forth lightnings ... do you know the ordinances of heaven and can you establish their rule on the earth?' (38:35, 33).</p>",
    "11": "<p><strong>lāśûm šəp̄ālîm ləmārôm wəqōḏərîm śāgəbû yešaʿ</strong>: 'to set on high those who are lowly, and those who mourn are lifted to safety.' The reversal of fortunes motif (<em>šəp̄ālîm</em> = low ones raised; <em>qōḏərîm</em> = those in mourning/dressed in dark sackcloth, lifted) is a cornerstone of biblical theology of divine justice (cf. 1 Sam 2:7-8 in Hannah's song; Luke 1:52 in the Magnificat). YHWH characteristically reverses social stratifications — the proud brought low, the humble exalted. Eliphaz uses this to suggest that if Job humbles himself (submits to discipline), God will restore him. This theological point is not wrong in itself — the error is the application to Job's specific case as a formula.</p>",
    "12": "<p><strong>mēp̄êr maḥšəḇôṯ ʿărûmîm wəlōʾ-taʿăśênāh yəḏêhem tûšiyyāh</strong>: 'He frustrates the devices of the crafty, so that their hands achieve no success.' The vocabulary here is wisdom-register: <em>ʿărûmîm</em> (crafty/shrewd, the same word as the serpent in Gen 3:1) and <em>tûšiyyāh</em> (abiding success/sound wisdom, a wisdom-literature term, appearing also in Job 11:6; 12:16; Prov 2:7; 3:21; 8:14). God is the one who unravels the schemes of those who use cleverness without reverence. This is the wisdom teaching that human strategy ultimately cannot prevail against divine sovereignty — a point Paul cites in 1 Cor 3:19 from v.13.</p>",
    "13": "<p><strong>lōkēḏ ḥăkāmîm bəʿormāṯām wăʿăṣaṯ nip̄tālîm niməhārāh</strong>: 'He catches the wise in their own craftiness, and the schemes of the wily are brought to a quick end.' <em>ʿormāh</em> (craftiness) is the instrument of their own entrapment: divine irony uses the wicked's own cleverness as the net. The hapax <em>nip̄tālîm</em> (twisted/wily ones, from <em>pāṯal</em> = to twist, wrestle) appears in Gen 30:8 of Jacob's wrestling and in Prov 8:8 of perverse speech. Paul quotes v.13 in 1 Cor 3:19 ('He catches the wise in their craftiness') as part of his argument that worldly wisdom is foolishness before God — a direct citation that establishes Paul's awareness of the Job context and its anti-sophistry thrust.</p>",
    "14": "<p><strong>yômām yip̄gəšû-ḥōšeḵ ûḵallaylāh yəmašəšû ḇaṣṣohărāyim</strong>: 'They meet with darkness in the daytime and grope at noonday as in the night.' The inversion of light/dark (day becomes darkness, noon becomes night-groping) echoes the Deuteronomic covenant curse: 'You shall grope at noonday, as the blind grope in darkness' (Deut 28:29). This is covenant-curse language applied to the crafty enemies of God — a bold claim that the wicked are experiencing the darkness of divine judgment even in their apparent success. The image of groping in darkness will recur in Job 12:25 where Job applies it to YHWH's sovereign confusion of the mighty.</p>",
    "15": "<p><strong>wayyōšaʿ mēḥereḇ mippîhem ûmiyadꞌ ḥāzāq ʾeḇyôn</strong>: 'But he saves the needy from the sword of their mouth and from the hand of the mighty.' The transition from the wicked being frustrated (vv.12-14) to the needy being saved completes the reversal structure: God confounds the powerful and delivers the powerless. <em>ʾeḇyôn</em> (the needy/destitute) is the standard vocabulary in the Psalms and prophets for the socially vulnerable who depend entirely on divine justice (Ps 9:18; 12:5; 35:10; Amos 2:6; Isa 25:4). The <em>ḥereḇ pîhem</em> (sword of their mouth) anticipates the NT's metaphor of the word as a sword (Heb 4:12; Rev 1:16).</p>",
    "16": "<p><strong>wattəhî laddal tiqwāh wəʿolātāh qāp̄əṣāh-pîhā</strong>: 'So the poor have hope, and injustice shuts her mouth.' The verse summarizes the theodicy argument of vv.11-16: divine action on behalf of the lowly generates hope (<em>tiqwāh</em>) for the <em>dal</em> (poor/weak) and silences <em>ʿolātāh</em> (injustice, wrongdoing — from <em>ʿāwal</em>, to be crooked/unjust). Injustice is personified as a speaker whose mouth is shut — a courtroom image. The hope of the poor is a crucial OT theological motif (cf. Ps 9:18: 'For the needy shall not always be forgotten, and the hope of the poor shall not perish forever'). Eliphaz uses this as comfort for Job, assuming Job is among the poor who will be vindicated — if he submits.</p>",
    "17": "<p><strong>hinnēh ʾašrê ʾěnôš yôkiḥennû ʾělôah ûmûsar šadday ʾal-timʾās</strong>: 'Behold, blessed is the one whom God reproves; therefore despise not the discipline of the Almighty.' The <em>ʾašrê</em> formula (beatitude: blessed/happy is...) is the opening of Psalm 1 and a key wisdom genre marker. Applied here to the one who receives divine reproof (<em>yāḵaḥ</em>), it presents suffering-as-discipline as a mark of divine favor. <em>Šadday</em> (the Almighty, El Shaddai) is the primary divine name in Job's poetic sections (31 of the 48 OT occurrences are in Job) — likely reflecting the wisdom literature's use of a more universal divine name appropriate to a non-Israelite setting. Hebrews 12:5-6 quotes this verse directly: 'My son, do not regard lightly the discipline of the Lord, nor be weary when reproved by him. For the Lord disciplines the one he loves.' The NT citation transforms the verse from retribution comfort into positive theology of sonship.</p>",
    "18": "<p><strong>kî hûʾ yakʾîḇ wəyeḥbāš yimḥaṣ wəyādāyw tirp̄ênāh</strong>: 'For he wounds, but he binds up; he shatters, but his hands heal.' The divine antithesis (wound/bind, shatter/heal) is a foundational OT theological pattern: YHWH kills and makes alive (Deut 32:39; 1 Sam 2:6); he brings down to Sheol and raises up. The verbs <em>ḵāʾaḇ</em> (to be in pain, cause pain) and <em>ḥāḇaš</em> (to bind up, as a wound) describe the same medical action — infliction followed by treatment. The theological claim is that divine judgment and divine restoration come from the same hands: suffering is not evidence of abandonment but of active divine engagement. This verse underpins the book's theodicy: the hands that wound are the hands that will bind — but the timing is God's, not ours.</p>",
    "19": "<p><strong>ḇəšēš ṣārôṯ yaṣṣîleḵā ûḇəšeḇaʿ lōʾ-yiggaʿ bəḵā rāʿ</strong>: 'He will deliver you from six troubles; in seven no evil shall touch you.' The numerical saying (x, x+1) is a classic wisdom literary form (cf. Prov 6:16: six things YHWH hates, seven are an abomination; Amos 1:3: for three transgressions, for four; Eccl 11:2). The pattern implies completeness-beyond-completeness: no matter how many troubles come, YHWH delivers. The sevenfold structure frames vv.20-22 as illustrations. The verse is genuine pastoral comfort but employs a formula that, as the epilogue shows, Job's friends applied mechanically rather than discerningly.</p>",
    "20": "<p><strong>ḇərāʿāḇ pāḏəḵā mimmāweṯ ûḇamilḥāmāh mîyəḏê-ḥāreḇ</strong>: 'In famine he will redeem you from death, and in war from the power of the sword.' The verb <em>pāḏāh</em> (redeem, ransom) is the commercial/legal term for buying someone out of slavery or death-obligation. It is used in the OT for YHWH's ransoming Israel from Egypt (Deut 7:8; 15:15) and will be used by Job himself in the hope that his <em>gōʾēl</em> (kinsman-redeemer, 19:25) will vindicate him. The pairing of famine and sword echoes the classic triad of divine judgment (sword, famine, pestilence, cf. Jer 14:12; Ezek 5:12) — but here reversed into forms of divine deliverance.</p>",
    "21": "<p><strong>bəšōṭ lāšôn tiṣṣāp̄ēn wəlōʾ-ṯîrāʾ mîššōḏ kî yāḇôʾ</strong>: 'You shall be hidden from the lash of the tongue, and shall not fear destruction when it comes.' <em>Šôṭ lāšôn</em> (scourge/lash of the tongue) is a vivid hapax for the destructive power of slander or false accusation. <em>Šōḏ</em> (destruction, devastation) is a standard prophetic term for sudden ruin (Isa 13:6; Joel 1:15; Zeph 1:15, where it occurs in the formula <em>šōḏ miššadday</em>, destruction from the Almighty). The promise of protection from tongue-violence is especially resonant in Job's situation: in the dialogues, the friends' words themselves become a kind of scourging.</p>",
    "22": "<p><strong>ləšōḏ ûlərāʿāḇ tiśḥāq ûmijjayaṯ hāʾāreṣ ʾal-ṯîrāʾ</strong>: 'At destruction and famine you shall laugh, and shall not fear the beasts of the earth.' The image of laughing at destruction (<em>śāḥaq</em>) echoes the leviathan's response to Job's weapons in the whirlwind speech (41:29: 'He laughs at the rattle of the javelin'). The restoration of the righteous reverses the threat: what once brought terror becomes occasion for confident laughter. The promise of peace with nature's beasts (v.23) continues the Edenic-restoration imagery that appears throughout the OT in descriptions of eschatological restoration (Isa 11:6-9; 65:25).</p>",
    "23": "<p><strong>kî ʿim-ʾaḇnê haśśāḏeh bəriṯeḵā ûḥayyaṯ haśśāḏeh hišlěmāh-lāḵ</strong>: 'For you shall be in league with the stones of the field, and the beasts of the field shall be at peace with you.' The covenant (<em>bərît</em>) with stones is unusual and debated — it may mean either a covenant of safety with the land itself (stones/rocks as obstacles removed) or an alliance metaphor (the land's hostility is dissolved). The <em>šālôm</em>-peace with wild animals evokes Hosea 2:18's eschatological covenant: 'I will make for them a covenant on that day with the beasts of the field, the birds of the heavens, and the creeping things of the ground.' The restoration language anticipates the new creation's peace but Eliphaz applies it pragmatically as a condition of Job's repentance-and-restoration.</p>",
    "24": "<p><strong>wəyāḏaʿtā kî-šālôm ʾohŏleḵā ûp̄āqaḏtā nāweḵā wəlōʾ ṯeḥeṭāʾ</strong>: 'You shall know that your tent is at peace, and you shall inspect your fold and miss nothing.' <em>Šālôm</em> (wholeness, peace, well-being) of the tent is the culminating domestic image of restoration — the home as secure refuge. The verb <em>pāqaḏ</em> (to visit, inspect, take inventory) when applied to flocks means to count and find everything present. <em>Nāweh</em> (dwelling, fold, pasture) is the same word used in v.3 of the fool whose dwelling was cursed — the contrast is deliberate: repent, and your <em>nāweh</em> will be inspected with satisfaction rather than cursed.</p>",
    "25": "<p><strong>wəyāḏaʿtā kî-raḇ zarʿeḵā ûṣeʾěṣāʾeḵā kəʿēśeḇ hāʾāreṣ</strong>: 'You shall know also that your offspring shall be many, and your descendants as the grass of the earth.' The restoration of children and descendants completes the picture: the specific losses of Job's prologue (children killed, 1:18-19) are directly addressed. The comparison to grass (<em>ʿēśeḇ hāʾāreṣ</em>) echoes the Abrahamic blessing language — offspring as innumerable as stars/sand/dust (Gen 13:16; 15:5; 22:17). Eliphaz presents the covenant blessing pattern as the natural result of submission to discipline. The epilogue does in fact restore Job's children (42:13-16), but not through Eliphaz's mechanism of formulaic repentance.</p>",
    "26": "<p><strong>tāḇôʾ ḇeqeleḥ ʾeleyqāḇer kiʿălôṯ gāḏîš bəʿittô</strong>: 'You shall come to your grave in ripe old age, like a sheaf gathered up in its season.' <em>Qeleḥ</em> (ripe age, full vigor) is a hapax legomenon describing the peak of physical maturity — death at the right time, not prematurely. The agricultural simile (<em>gāḏîš</em>, a harvest stack/shock of grain) gathered <em>bəʿittô</em> (in its season/time) is the ideal death: the full-term harvest, not green grain cut down untimely. This directly addresses Job's earlier lament about dying in misery (3:11: 'Why did I not die at birth?'). The ideal death in wisdom literature is the <em>śeḇaʿ yāmîm</em> (full of days, Gen 35:29; Job 42:17) — Job's restoration will fulfill exactly this promise.</p>",
    "27": "<p><strong>hinnēh-zōʾṯ ḥăqarnûhā kēn-hîʾ šəmaʿāh wəʾattāh ḏaʿ-lāḵ</strong>: 'Behold, this we have searched out; it is true. Hear, and know it for your good.' Eliphaz closes his speech with an appeal to communal investigation: <em>ḥāqar</em> (to search out, investigate) is the wisdom vocabulary for careful inquiry (Job 8:8; Prov 25:2; Eccl 1:13). The plural 'we have searched' invokes the authority of the wisdom tradition — these are not Eliphaz's personal opinions but the collected findings of the sages. The final imperative <em>ḏaʿ-lāḵ</em> (know it for yourself, take it to heart) is pastoral but also condescending: Eliphaz presents himself as transmitting received wisdom to an ignorant sufferer. YHWH's verdict in 42:7 will demolish this claim to certainty.</p>"
  },
  "6": {
    "1": "<p><strong>wayyaʿan ʾiyyôḇ wayyōʾmar</strong>: Standard dialogue formula introducing Job's reply. The verb <em>ʿānāh</em> (to answer, respond) followed by the verb of speech is the LXX's standard rendering throughout the dialogues. Job's reply (chs. 6-7) has two distinct movements: an address to the three friends (6:1-30) defending the legitimacy of his complaint, and a direct address to God (7:1-21) that is essentially a lament psalm. The shift in addressee (human interlocutors → God) is a key structural feature of the dialogue sections.</p>",
    "2": "<p><strong>lû-šāqôl yiššāqēl kaʿaśî wəhawwāṯî ḇammōʾznayim yiśśāʾû yaḥaḏ</strong>: 'Oh that my vexation were weighed, and all my calamity laid in the balances.' The weighing image (<em>šāqal</em>, to weigh; <em>mōʾznayim</em>, scales/balances) invokes the Egyptian judgment scene but also the wisdom tradition of measuring evidence carefully. <em>Kaʿaś</em> (vexation, grief, provocation) is the same word Eliphaz used in 5:2 as the emotion that kills the fool — Job takes that word and proposes to weigh it objectively. <em>Hawwāh</em> (calamity, ruin) is a strong term (cf. Ps 5:9; 52:2; 55:11; Prov 17:4). Job's argument: if his distress were actually measured, the friends would understand why his words have been extreme.</p>",
    "3": "<p><strong>kî-ʿattāh mîḥôl yammîm yiḵbād ʿal-kēn ḏəḇāray lāʿû</strong>: 'For then it would be heavier than the sand of the sea; therefore my words have been rash.' The comparison to sand (<em>ḥôl yammîm</em>, sand of the sea) invokes the Abrahamic innumerable-descendants image but reverses it: Job's suffering outweighs even the immeasurable. <em>Lāʿû</em> (rash, impetuous — from <em>lûaʿ</em>, to swallow/gulp) is a self-critique: Job admits his words have been hasty. This is not a retraction of their content (he will maintain his innocence throughout) but an acknowledgment that extreme suffering produces extreme speech — and that extreme speech deserves the weight of the suffering that produced it, not the dismissal Eliphaz offered.</p>",
    "4": "<p><strong>kî ḥiṣṣê šadday ʿimmāḏî ʾăšer ḥămaṯām šōṯāh rûḥî biʿûṯê ʾělôah yaʿărəḵûnnî</strong>: 'For the arrows of the Almighty are in me; my spirit drinks their poison; the terrors of God are arrayed against me.' This is one of Job's most intense images. <em>Ḥiṣṣê šadday</em> (arrows of the Almighty) is warrior-deity imagery: God as divine archer whose arrows have found their mark in Job. The image of <em>ḥamāh</em> (poison/venom) drunk by the spirit extends the metaphor — these are envenomed arrows. <em>Biʿûṯê ʾělôah</em> (terrors of God) uses the rare <em>biʿûṯāh</em> (a terrifying event, hapax) for divine assault. Job is not complaining about natural illness but about experienced divine aggression — a theological claim of the highest seriousness. The friends interpret suffering as consequence of sin; Job experiences it as direct divine action, which he cannot reconcile with his innocence.</p>",
    "5": "<p><strong>hăyinʿaq-pereʾ ʿălê-ḏešeʾ ʾim-yigʿeh-šôr ʿal-bəlîlô</strong>: 'Does the wild donkey bray when he has grass, or the ox low over his fodder?' The first of two animal analogies defending the naturalness of complaint under extreme conditions. The wild ass (<em>pereʾ</em>) only brays when it lacks grass; the ox only lows when its feed (<em>bəlîl</em>, mixed fodder) is absent. Job's argument: my cries are not complaints without cause — they are the natural sound of an animal in genuine distress. The analogy disarms the friend's criticism by appealing to observable animal behavior: complaint is evidence of need, not of character deficiency. This is a more honest account of lament than Eliphaz's formula allows.</p>",
    "6": "<p><strong>hăyēʾāḵēl ṯāp̄ēl mibbəlî-mālaḥ ʾim-yēš-ṭaʿam bəriyr ḥallāmûṯ</strong>: 'Can that which is tasteless be eaten without salt, or is there any taste in the juice of the mallow?' The second food analogy shifts from animal hunger to human appetite. <em>Ṯāp̄ēl</em> (insipid, tasteless, a hapax) describes food that cannot be eaten without <em>mālaḥ</em> (salt), the standard preservative and flavor-agent of the ancient world. <em>Ḥallāmûṯ</em> (mallow/purslane) is another hapax; its juice was considered medicinal but bitter. Job's point: just as tasteless food requires salt to be acceptable, his extreme words are the natural seasoning of unbearable suffering. He is not apologizing for his speech but contextualizing it.</p>",
    "7": "<p><strong>mēʾănāh lānəgôaʿ nap̄šî hēmmāh kidwê laḥmî</strong>: 'My appetite refuses to touch them; they are as food that is loathsome to me.' <em>Nep̄eš</em> (here rendered 'appetite,' but also soul/self/desire) refuses (<em>māʾan</em>) the friends' counsel because it is loathsome (<em>dōweh</em>, sick, faint, also used of menstrual illness, Lev 15:33, Lam 1:13 — a term of visceral revulsion). The verse connects back to the food imagery of vv.6-7: just as tasteless food is unpalatable, the friends' words are nauseating in their inadequacy. The self is not merely intellectually disagreeing with the friends but experiencing their counsel as physically repellent — a sign of the depth of his suffering and their failure to reach him.</p>",
    "8": "<p><strong>mî-yiṯṯēn ṯāḇôʾ šeʾělāṯî wəṯiqwāṯî yiṯṭēn ʾělôah</strong>: 'Oh that I might have my request, and that God would fulfill my hope.' The <em>mî-yiṯṯēn</em> (who will grant? / oh that!) formula is Job's characteristic expression of desperate longing (cf. 11:5; 13:5; 14:4, 13; 19:23; 23:3; 29:2). It signals a wish for something that seems impossible given the current situation. <em>Šeʾělāh</em> (request, petition) and <em>tiqwāh</em> (hope, expectation) pair the specific petition with the underlying orientation of faith: Job still expects something from God, even in extremity. His hope (<em>tiqwāh</em>) is not yet extinguished — which is why the specific content of the wish (death, v.9) is so stark.</p>",
    "9": "<p><strong>wəyōʾēl ʾělôah wîdakkəʾēnî yatṭēr yāḏô wîḇaṣṣəʿēnî</strong>: 'that it would please God to crush me, that he would let loose his hand and cut me off.' The wish is for death by divine action: <em>dāḵāʾ</em> (to crush, oppress; the same root as the children 'crushed in the gate' in 5:4) and <em>bāṣaʿ</em> (to cut off/through, possibly from weaving: to cut the thread of life). Job does not wish for suicide but for God to complete what he has begun: if YHWH is against him, let the divine hand act decisively rather than prolonging the anguish. This is not despair without faith — it is a theodicy challenge: if God is going to crush me, do it; the prolonged suffering is the unbearable part.</p>",
    "10": "<p><strong>wəṯəhî ʿôḏ niḥāmāṯî waʾăsallēḏāh bəḥîlāh lōʾ-yaḥmôl kî-lōʾ kiḥaḏtî ʾimrê qāḏôš</strong>: 'This would be my comfort; I would even exult in pain unsparing, for I have not denied the words of the Holy One.' Remarkable: death would be Job's comfort (<em>niḥāmāh</em>, consolation). But the grounds are theologically significant: he has not denied (<em>kāḥaḏ</em>, to hide, deny, suppress) the words of the Holy One (<em>ʾimrê qāḏôš</em>). <em>Qāḏôš</em> as a divine epithet is relatively rare in Job and occurs here as a term of absolute divine holiness. Job's innocence is grounded not in moral self-righteousness but in fidelity to divine speech: he has not suppressed or denied God's word. This is the book's central claim: suffering does not require either denial of God or denial of one's integrity.</p>",
    "11": "<p><strong>māh-kōḥî kî-ʾăyaḥēl ûmah-qiṣṣî kî-ʾaʾărîḵ nap̄šî</strong>: 'What is my strength, that I should wait? And what is my end, that I should be patient?' The rhetorical questions confront the friends' demand for patience with physical and existential realism. <em>Kōaḥ</em> (strength, power) and <em>qēṣ</em> (end, limit) define the parameters of endurance: how much strength does a man have, and what end justifies the suffering? The verb <em>yāḥal</em> (to hope, wait) is the standard wisdom-psalm term for patient trust (Ps 27:14; 31:24; 33:18, 20, 22; 130:5, 7). Job is not rejecting hope in God but challenging the friends' easy prescription of patience by asking: what does patience look like when strength is gone?</p>",
    "12": "<p><strong>ʾim-kōḥ ʾăḇānîm kōḥî ʾim-bəśārî nāḥûš</strong>: 'Is my strength the strength of stones, or is my flesh bronze?' The rhetorical answer is obvious: no. <em>ʾăḇānîm</em> (stones) and <em>nāḥûš</em> (bronze/copper) represent indestructible materials — the human body is neither. The question exposes the unrealism of the friends' counsel: they prescribe endurance for a body that is flesh and blood, not stone and bronze. The image will recur in the Servant Songs: 'I have set my face like a flint' (Isa 50:7), where resolution in suffering requires divine strengthening precisely because human flesh is not stone.</p>",
    "13": "<p><strong>hăʾim ʾên ʿezrāṯî ḇî wəṯûšiyyāh niḏḏəḥāh mimmennî</strong>: 'Have I any help in me, when resource is driven from me?' <em>ʿEzrāh</em> (help, resource within oneself) and <em>tûšiyyāh</em> (abiding success/sound wisdom, the same wisdom term as in 5:12) are both absent. Job is not feigning weakness as a rhetorical move — he is diagnosing his actual condition: all inner and outer resources have been expelled (<em>nāḏaḥ</em>, driven away). The verse bridges from Job's self-assessment (vv.11-12) to his indictment of the friends (v.14ff): when a man has no internal resource left, what he needs is <em>ḥeseḏ</em> from a friend, not reproof.</p>",
    "14": "<p><strong>lammās mērēʿēhû ḥāseḏ wəyirʾaṯ šadday yaʿăzôḇ</strong>: 'He who withholds kindness from a friend forsakes the fear of the Almighty.' One of Job's most theologically dense verses. <em>Ḥeseḏ</em> (covenant lovingkindness, steadfast loyalty) is the defining term of YHWH's covenant character (Exod 34:6-7) and is here claimed as an obligation owed between friends. To withhold <em>ḥeseḏ</em> from a <em>mās</em> (one who is dissolving/despairing — the participle of <em>māsas</em>, to dissolve, melt) is to <em>ʿāzaḇ</em> (forsake) the fear of the Almighty: cruelty to a suffering friend is tantamount to apostasy. The verse inverts the friends' logic: they claimed Job's suffering proves his sin; Job claims the friends' failure of <em>ḥeseḏ</em> proves their unfaithfulness. The NT fulfillment: Christ's <em>ḥeseḏ</em> toward the suffering is the embodiment of this verse (Matt 11:28-29).</p>",
    "15": "<p><strong>ʾaḥay ḇāgəḏû kəmô-nāḥal kiʾăp̄îqê nəḥālîm yaʿăḇōrû</strong>: 'My brothers are treacherous as a torrent-bed, as torrential streams that pass away.' The wadi metaphor begins: <em>nāḥal</em> (wadi, seasonal stream channel) and <em>ʾāp̄îq</em> (water channel, river-bed) are terms for the wadis of the Levant and Sinai — dry beds that flood dramatically in rainy season and run completely dry in summer. The simile indicts the friends for the most fundamental form of relational betrayal: they present themselves as reliable support but, like wadis, are present only when conditions are favorable. <em>Bāgaḏ</em> (treacherous, to deal deceitfully) is the term used for covenant betrayal (Jer 3:20; Hos 5:7; Mal 2:10, 11, 14, 15, 16).</p>",
    "16": "<p><strong>haqqōḏərîm miqqāraḥ ʿălêhem yiṯʿallam-šāleḡ</strong>: 'which are dark with ice, and where the snow hides itself.' The wadi in winter/early spring: black with melted snow and hidden ice (<em>qāraḥ</em>, ice/frost). The streams appear full and reliable — but this is temporary, as vv.17-20 explain. The word <em>yiṯʿallam</em> (to hide itself, conceal) will recur in Job's speeches in the context of God's hiddenness (13:24: 'Why do you hide your face?'). The wadi that hides its snow/reliability anticipates God's hiddenness as another form of the friends' unreliability — or perhaps vice versa.</p>",
    "17": "<p><strong>bəʿēṯ yəzōrəbû niṣmāṯû bəḥummô dāʿăkû mimməqômām</strong>: 'When they melt, they disappear; when it is hot, they vanish from their place.' The summer reversal: <em>zāraḇ</em> (to scorch, cause to vanish through heat) and <em>dāʿaḵ</em> (to be quenched, extinguished — used of lamplight going out, Prov 13:9; 20:20) describe the wadi's summer disappearance. The very heat that travelers hope will make a stream more accessible dries it completely. The theology of the friends as wadis: they appeared reliable in comfortable times; Job's extreme suffering is the summer heat that revealed their absence. Real friendship, like real <em>ḥeseḏ</em>, must survive the heat.</p>",
    "18": "<p><strong>yiləpəṯû ʾorḥôṯ darkām yaʿălû ḇattōhû wayyōʾḇēḏû</strong>: 'The caravans of Tema look, the travelers of Sheba hope.' Wait — this verse reads: 'the caravans turn aside from their paths; they go up into the waste and perish.' The travelers — not yet mentioned — are arriving at a wadi that has gone dry. <em>Ṯēmāʾ</em> (Tema) is the Arabian trading station (Job 1:15; Isa 21:14; Jer 25:23) and <em>Šəḇāʾ</em> (Sheba) is the South Arabian trading kingdom (Job 1:15; 1 Kgs 10:1-13): both are trading routes dependent on water sources. When the expected wadi is dry, the caravan must abandon its planned route and perish in the desert (<em>tōhû</em>, the wasteland — the same word as Gen 1:2's formless void).</p>",
    "19": "<p><strong>ḥăḇallôṯ ṯēmāʾ hibbiṭû ʾorḥôṯ šəḇāʾ qiwwû-lāmô</strong>: 'They are ashamed because they were confident; they come there and are disappointed.' The merchants' confidence (<em>bāṭaḥ</em>, to trust, rely on) turns to <em>ḇōšāh</em> (shame, disappointment) — the covenantal vocabulary of trust betrayed. The wadi that promised water delivered nothing. The traveler's expectation (<em>qāwāh</em>, to wait/hope/expect) was false. Job applies this directly to his own experience of the friends: he came to them in distress, expecting the <em>ḥeseḏ</em> that friends owe; he received reproof instead. His disappointment is not petulance but the deep disorientation of betrayed trust.</p>",
    "20": "<p><strong>kî-yāḵēlû bāṭaḥ bāhū wîʾātā-ʿāḏêhā wayḇōšû</strong>: 'For you have now become nothing; you see my calamity and are afraid.' The application becomes explicit: <em>ʾattāh</em> (you — plural, addressing the friends directly) are nothing (<em>lōʾ-hāyāh</em> in v.21 makes this clearer). The verb <em>yārēʾ</em> (to be afraid) suggests that the friends are frightened by Job's calamity: his radical suffering threatens their retribution theology. If Job suffers, and Job is innocent, then the theology that suffering = sin is false — and their own security is threatened. The friends' unwillingness to offer <em>ḥeseḏ</em> may be partly defensive: to defend Job's innocence would require dismantling their own framework.</p>",
    "21": "<p><strong>kî-ʿattāh hĕyîṯem lōʾ tirʾû ḥāṯaṯ wayyîrāʾû</strong>: 'Such you have become to me; you see my terror, and you are afraid.' The final diagnosis: the friends have become (<em>hāyāh lĕ-</em>) to Job what the dry wadi is to the caravan — nothing where there should have been water. Their fear (<em>ḥāṯaṯ</em>, dismay/shattered confidence; <em>yārēʾ</em>, afraid) is the response of men whose theological system is destabilized by Job's case. Job's 'terror' (<em>ḥittat</em>) is the very extremity that should have activated their <em>ḥeseḏ</em> — instead it activated their self-protective theology.</p>",
    "22": "<p><strong>hăkî ʾāmartî hāḇû-lî wûmiḵōḥăkem šiḥăḏû ḇaʿăḏî</strong>: 'Have I said, \"Make me a gift\"? Or, \"From your wealth offer a bribe for me\"?' Job's forensic challenge: he is not asking for money (<em>maṯṯān</em>, a gift/bribe) or intercession through payment (<em>šōḥad</em>, a bribe/present). He wants something more costly: honesty. The introduction of bribery vocabulary (<em>šōḥad</em>) is significant — Job is not manipulating the friends for financial advantage; he is asking for the <em>ḥeseḏ</em> that costs nothing and yet is beyond their capacity to give: recognition of his innocence.</p>",
    "23": "<p><strong>wûmiyyadꞌ-ṣar palṭûnî ûmiyyad ʿārîṣîm tipdûnî</strong>: 'Or, \"Deliver me from the adversary's hand\"? Or, \"Redeem me from the hand of the ruthless\"?' Job's forensic defense continues: he has asked for no material favor, no political intercession, no rescue from enemies. The vocabulary of rescue (<em>pālaṭ</em>, to deliver; <em>pāḏāh</em>, to ransom/redeem) would normally describe prayers for divine deliverance — Job applies it to what he could have asked of the friends but didn't. His actual request is simpler and harder: tell me where I went wrong.</p>",
    "24": "<p><strong>hôrûnî waʾănî ʾaḥărîš ûmah-šāḡîṯî hāḇînû lî</strong>: 'Teach me, and I will be silent; make me understand how I have gone astray.' A genuine opening: Job commits to silence and learning if the friends can demonstrate his specific sin. <em>Šāgāh</em> (to wander astray, to err) is the verb for inadvertent moral error (Num 15:22; Ps 119:21, 118) rather than deliberate rebellion. Job is not claiming absolute sinlessness — he is claiming he is not aware of the specific sin that could account for his suffering. The offer of silence (<em>ḥārîš</em>) in exchange for evidence is a forensic proposition: show me the evidence, and I will concede. The friends never accept this challenge on its terms.</p>",
    "25": "<p><strong>māh-niməṣû diḇrê-yōšer ûmāh-yôkîaḥ hôkēaḥ mikkkem</strong>: 'How forceful are upright words! But what does reproof from you reprove?' <em>Niməṣû</em> (are powerful, from <em>māraṣ</em> — to be sharp, strong, forceful) is used only a few times in Job (16:3; 1 Kgs 2:8). Upright (<em>yōšer</em>) words have genuine force; but the friends' reproof (<em>hôkîaḥ</em>, the same verb as disciplinary reproof in 5:17) has no power because it is not upright. The paradox: the friends claim to be offering true wisdom (as Eliphaz presented it in 5:27 as searched-out truth), but Job claims their reproof fails to reprove because it does not match his actual case.</p>",
    "26": "<p><strong>halhôkîaḥ millîm taḥšōḇû wələrûaḥ ʾimrê nōʾāš</strong>: 'Do you think that you can reprove words, when the speech of a despairing man is wind?' The verbal reproof of a <em>nōʾāš</em> (despairing one, from <em>yāʾaš</em> — to despair, be without hope) is like criticizing wind: the wind cannot help its direction. <em>Rûaḥ</em> (wind/spirit/breath) here means the naturally uncontrolled outflow of despair. Job's defense of his extreme language: to reprove the speech of a despairing man is to miss the point — the speech is evidence, not sin; the despair requires comfort, not correction. The same point John Calvin makes in his commentary: 'It is unreasonable to require from the sick the same moderation as from those who are well.'</p>",
    "27": "<p><strong>ʾap̄-ʿal-yāṯôm tappîlû wətiḵrû ʿal-rēʿăkem</strong>: 'You would even cast lots over the fatherless, and bargain over your friend.' The accusation escalates to its sharpest point: the friends are behaving like those who gamble over a fatherless child's inheritance (<em>yāṯôm</em>, orphan — the most vulnerable category in OT law) and make commercial transactions over their friend (<em>kārāh</em>, to dig/trade/bargain). The image of casting lots over the helpless will be fulfilled with horrific literalism at the crucifixion (Ps 22:18; John 19:24: 'they divided my garments among them and for my clothing they cast lots'). Job, stripped of everything, is being treated like the destitute — by his own friends.</p>",
    "28": "<p><strong>wəʿattāh hôʾîlû p̄ənû-ḇî wəʿal-p̄ənêkem ʾim-ʾăḵazzēḇ</strong>: 'But now, be pleased to look at me, for I will not lie to your face.' The appeal to direct confrontation: <em>p̄ānāh</em> (to turn toward, face) and <em>ʾim-ʾăḵazzēḇ</em> (I will not lie, the conditional absolute oath). Job invites the friends to look at him directly — not through their theological framework — and commits his own speech to truthfulness. The contrast with the friend's wadi-like unreliability (v.15) is pointed: Job remains transparent even when they do not. The appeal for direct eye contact is a demand for person-to-person engagement over abstract theological dispute.</p>",
    "29": "<p><strong>šûḇû-nāʾ ʾal-tehî ʿawlāh wəšûḇû ʿôḏ ṣiḏqî-ḇāh</strong>: 'Please turn; let no injustice be done. Turn now; my vindication is at stake.' The repeated <em>šûḇ</em> (turn back, return) is the standard repentance/return verb — here Job uses it against the friends: they need to repent of their false accusation. <em>ʿawlāh</em> (injustice, perversity) is what is being done to Job through false verdicts. <em>Ṣiḏqî-ḇāh</em> (my righteousness is still there/in it) is a claim that Job's integrity is at stake in this dispute — not just his feelings but his covenantal standing before God. The forensic register is fully deployed: Job is not merely complaining, he is making a legal claim.</p>",
    "30": "<p><strong>hăyēš-bəlāšônî ʿawlāh ʾim-ḥikkî lōʾ-yāḇîn hawwôṯ</strong>: 'Is there any injustice on my tongue? Cannot my palate discern calamity?' Job closes his address to the friends with a self-appeal to sensory discernment: his tongue (<em>lāšôn</em>) is not producing <em>ʿawlāh</em> (injustice/perversity) and his palate (<em>ḥēḵ</em>) can distinguish <em>hawwôṯ</em> (calamity, a strong word for ruin — same root as v.2's 'calamity'). The taste metaphor connects back to the food imagery of vv.5-7: just as the palate can distinguish between food that is wholesome and food that is corrupt, Job's palate can distinguish between genuine calamity and imagined complaint. His speech is not corrupt; it is the accurate report of what a discerning palate has tasted.</p>"
  },
  "7": {
    "1": "<p><strong>hălōʾ-ṣāḇāʾ lěʾěnôš ʿal-ʾāreṣ waḵîmê śāḵîr yāmāyw</strong>: 'Has not man a hard service on earth, and are not his days like the days of a hired hand?' <em>Ṣāḇāʾ</em> (hard service, military conscription, compulsory service) is the term used for the Levites' temple service (Num 4:3, 23, 30, 35, 39, 43) and for military service (Num 1:3; 31:3). When applied to human existence generally, it frames life itself as involuntary conscription into a campaign with no discharge. <em>Śāḵîr</em> (hired laborer, day-worker) adds the dimension of economic servitude: both the soldier and the day-worker live entirely at the disposal of another, waiting for the day to end. Job's first verse of his divine soliloquy frames the entire human condition as servitude — a searing counter to the creation theology that calls humanity the crown of creation (Gen 1:26-28; Ps 8:4-8).</p>",
    "2": "<p><strong>kəʿeḇeḏ yišʾap̄ ṣēl wəḵəśāḵîr yəqawweh pōʿolô</strong>: 'Like a slave who longs for the shadow, and like a hired hand who looks for his wages.' <em>ʾĀḇeḏ</em> (slave) and <em>śāḵîr</em> (hired laborer) continue the labor metaphor. The slave longs for <em>ṣēl</em> (shade — the midday rest that provides relief from the killing sun) and the day-worker longs for <em>pōʿăl</em> (wages — the moment of completion and reward). Both are endurance-under-duress: the slave endures the heat for the shade; the laborer endures the work for the wage. Job's comparison: his life is exactly this — endurance waiting for a relief that does not come (v.3: months of emptiness).</p>",
    "3": "<p><strong>kēn huḥlaḥtî yarhê-šāwəʾ wəlêlôṯ ʿāmāl sippərû-lî</strong>: 'so I am allotted months of emptiness, and nights of misery are apportioned to me.' The passive verb <em>huḥlaḥ</em> (allotted, from <em>nāḥal</em>, to inherit/receive as a portion) makes YHWH implicit subject: Job has been given an inheritance of <em>šāwəʾ</em> (emptiness, vanity, futility — the same root as Ecclesiastes' <em>šāwəʾ</em>). The months and nights are precisely counted: <em>sippərû-lî</em> (are numbered for me, apportioned to me by divine accounting). The verse is a deliberate echo of the creation week's structure (numbered days) but applied to suffering rather than good work — Job's existence is a creation-week of misery.</p>",
    "4": "<p><strong>ʾim-šāḵaḇtî wəʾāmartî māṯay ʾāqûm ûmiḏḏad-ʿereḇ wəśāḇaʿtî nəḏuḏîm ʿăḏê-nešep̄</strong>: 'When I lie down I say, \"When shall I arise?\" But the night is long, and I am full of tossing till the dawn.' The daily cycle of hope and disappointment: lying down triggers the wish for morning (<em>māṯay ʾāqûm</em>, when shall I rise?); but the evening (<em>ʿereḇ</em>) brings <em>nəḏuḏîm</em> (tossing, restlessness — from <em>nāḏaḏ</em>, to flee/wander) until dawn (<em>nešep̄</em>). Sleep, the natural human refuge from suffering, is denied. This insomnia-of-suffering becomes a liturgical image in the Psalms: 'in the night his song is with me' (Ps 42:8) and 'I call out by day but you do not answer, and by night, but I find no rest' (Ps 22:2).</p>",
    "5": "<p><strong>lāḇaš bəśārî rimmāh wəḡûš ʿāp̄ār ʿôrî rāgaʿ wayyimʾās</strong>: 'My flesh is clothed with worms and dirt; my skin hardens, then breaks out afresh.' The physical description of Job's illness: <em>rimmāh</em> (worms, maggots — associated with bodily decomposition, Exod 16:24; Isa 14:11; 66:24) clothing the flesh while living; <em>gûš ʿāp̄ār</em> (crusted with dirt/dust) and the skin cycle of hardening (<em>rāgaʿ</em>, to harden/close) and breaking open (<em>māʾas</em>, here: to run or break out afresh — disputed). The language anticipates the resurrection: the body being clothed with worms will one day be clothed with incorruption (1 Cor 15:53-54). The same Hebrew verb <em>lāḇaš</em> (clothed with) connects the present horror to the eschatological hope: what is now clothed with worms will be clothed with immortality.</p>",
    "6": "<p><strong>yāmay qallû miʾāreg wayyiḵlû bəʾep̄es tiqwāh</strong>: 'My days are swifter than a weaver's shuttle and come to their end without hope.' <em>ʾĀreg</em> (weaver's shuttle — the wooden implement that passes the weft thread through the warp at high speed) is one of three rapid-motion images Job uses for the passing of life (cf. 9:25-26: swifter than a runner, swift as papyrus boats, as an eagle swooping). The shuttle moves so quickly the eye can barely follow it. But the modifier is devastating: <em>bəʾep̄es tiqwāh</em> (with the ending of hope, without hope) — the swift passage of days is not the harmless speed of a full life but the exhaustion of hope. <em>ʾĚp̄es</em> (nothing, ceasing) qualifies <em>tiqwāh</em> (hope) as entirely spent.</p>",
    "7": "<p><strong>zəḵōr kî-rûaḥ ḥayyāy lōʾ-ṯāšûḇ ʿênî lirʾôṯ ṭôḇ</strong>: 'Remember that my life is a breath; my eye will never again see good.' The address shifts to God: <em>zəḵōr</em> (remember!) is the imperative plea of the lament psalms (Ps 25:6, 7; 74:2, 18, 22; 89:47, 50; 109:14; Lam 5:1) — calling YHWH to act by recalling the covenant. <em>Rûaḥ ḥayyāy</em> (breath of my life, spirit of my life) echoes the creation-breath of Gen 2:7 (<em>nišmaṯ ḥayyîm</em>). The plea grounds divine attention in the brevity of human life: 'Remember that I am a breath before you act.' The eye not seeing good (<em>ṭôḇ</em>) echoes the creation narrative's 'God saw that it was good' — Job is experiencing un-creation.</p>",
    "8": "<p><strong>lōʾ-ṯəšûrənî ʿên rōʾî ʿênêḵā bî wəʾênennî</strong>: 'The eye of him who sees me will behold me no more; while your eyes are on me, I shall be gone.' The verse has a double edge: the human eye (<em>ʿên rōʾî</em>, the eye of the one who sees me) will see him no more at death; but also: God's eyes (<em>ʿênêḵā</em>, your eyes) are fixed on Job — and if God does not act before Job dies, the opportunity for vindication is gone. The theological claim: the window for divine response is brief. Death is not the problem solved but the deadline missed. The urgency of the divine address in v.7-21 is entirely shaped by this: Job is dying, and God must act now or not at all.</p>",
    "9": "<p><strong>kālāh ʿānān wayyelāḵ kēn yôrēḏ šəʾôl lōʾ yaʿăleh</strong>: 'As the cloud fades and vanishes, so he who goes down to Sheol does not come up.' The cloud analogy (<em>ʿānān kālāh wayyelāḵ</em>, cloud that wastes away and goes) is an image of irreversible disappearance — the morning mist burned off by the sun. <em>Šəʾôl</em> (the realm of the dead) is the destination from which there is no return (<em>lōʾ yaʿăleh</em>, does not come up). Job's view here is entirely conventional pre-resurrection — death is final, the realm of the shades is one-directional. The NT's answer is Easter: 'But God raised him up, loosing the pangs of death, because it was not possible for him to be held by it' (Acts 2:24). Jesus's descent to and ascent from the place of the dead (<em>šəʾôl</em> in the OT, Hades in the LXX) is the direct reversal of the 'does not come up' of v.9.</p>",
    "10": "<p><strong>lōʾ-yāšûḇ ʿôḏ liḇêṯô wəlōʾ-yakkirennû ʿôḏ məqômô</strong>: 'he returns no more to his house, nor does his place know him anymore.' The permanence of death is extended to social erasure: the dead man's <em>bêṯ</em> (house/household) and <em>māqôm</em> (place) no longer recognize him. <em>Nāḵar</em> (to recognize, know by recognition) is used of social recognition — the dead man's household has moved on, his place is taken. This contrasts with 19:25-27 where Job's hope is for post-mortem vindication — here Job is focused on the urgency of divine action before that erasure occurs. The two passages together show Job's oscillation between despair (ch7) and faith (ch19).</p>",
    "11": "<p><strong>gam-ʾănî lōʾ ʾeḥśōk-pî ʾăḏabbərāh bəṣar rûḥî ʾāśîḥāh bəmar nap̄šî</strong>: 'Therefore I will not restrain my mouth; I will speak in the anguish of my spirit; I will complain in the bitterness of my soul.' The defiant turn: the brevity of life (vv.6-10) justifies unrestrained complaint. <em>Lōʾ ʾeḥśōk</em> (I will not restrain, from <em>ḥāśaḵ</em> = to withhold, spare) is the inverse of Eliphaz's call to patience. <em>Ṣar rûḥî</em> (narrowness/anguish of my spirit) and <em>mar nap̄šî</em> (bitterness of my soul) combine the physical sensation of choking constriction with the taste-metaphor of bitter suffering that appeared in the mallow-juice verse (6:7). The complaint that follows (vv.12-21) is addressed directly to God — a lament of forensic intensity.</p>",
    "12": "<p><strong>hăyām-ʾănî ʾim-tannîn kî-ṯāśîm ʿālay mišmār</strong>: 'Am I the sea, or a sea monster, that you set a guard over me?' <em>Yām</em> (sea — the cosmic sea of chaos in Canaanite mythology, the watery deep of Gen 1:2) and <em>tannîn</em> (sea monster/dragon — used in Ps 74:13; 89:10; Isa 27:1; 51:9 for the chaos creature defeated by YHWH at creation) are the mythological entities that require divine restraint. The theological implication: YHWH treats Job as though he were a chaos-threat requiring constant surveillance (<em>mišmār</em>, guard, watch). Job is not a cosmic monster — he is a suffering man. The accusation is that God's response to Job is categorically disproportionate: one does not keep a guard over a sick man as though he were the primordial sea.</p>",
    "13": "<p><strong>kî-ʾāmartî těnaḥăménî ʿarśî yiśśāʾ bəśîḥî miškaḇî</strong>: 'When I say, \"My bed will comfort me, my couch will ease my complaint.\"' Job reports the broken logic of the sufferer: the bed (<em>ʿereś</em>, couch/bed) was expected to provide comfort (<em>nāḥam</em>, the verb of consolation used throughout the psalms and prophets). The word <em>śîḥ</em> (complaint, meditation, speech — the same root as the Psalms' <em>śîaḥ</em>, 'pouring out my complaint to YHWH') shows that Job is not merely resting but lament-praying. But the bed does not bring comfort; instead (v.14) God terrifies him there. The expected sanctuary of sleep has been converted into a site of divine assault.</p>",
    "14": "<p><strong>waḥittaṯṯānî ḇaḥălōmôṯ ûmēḥezyônôṯ təḇaʿăṯennî</strong>: 'then you scare me with dreams and terrify me with visions.' <em>Bāʿaṯ</em> (to terrify, overwhelm — used of the dread of God's presence, Exod 15:14, 15; Ps 18:4; 83:15) and <em>ḥāṯaṯ</em> (to shatter, terrify — the antonym of Job's earlier wish for security) describe God's action in the sleep-realm. Dreams and visions (<em>ḥălômôṯ... ḥezyônôṯ</em>) were the standard media of divine communication in the OT (Gen 28; 37; 40-41; Num 12:6). Here Job experiences divine communication not as revelation but as terror. The irony is pointed: where the prophets received divine visions with awe and hope, Job receives them with dread — because the God he encounters in sleep is the same God who has destroyed him while awake.</p>",
    "15": "<p><strong>watiḇḥar maḥănāq nap̄šî māweṯ miʿaṣmôṯāy</strong>: 'so that I would choose strangling and death rather than my bones.' <em>Maḥănāq</em> (strangling) is a desperate image of death by asphyxiation — Job prefers this to continued existence in this body (<em>ʿaṣmôṯ</em>, bones, as the locus of life and vitality, cf. Ezek 37's valley of dry bones). The verse is not a suicidal threat in the modern clinical sense but a theological claim: the severity of divinely-inflicted suffering has crossed the threshold where the self chooses dissolution over continuation. This extreme language is what the friends will criticize as evidence of sin; YHWH's verdict in 42:7 will vindicate Job's honesty.</p>",
    "16": "<p><strong>māʾastî lōʾ-lěʿōlām ʾeḥyeh ḥăḏal mimmennî kî-heḇel yāmāy</strong>: 'I loathe my life; I would not live forever. Leave me alone, for my days are a breath.' <em>Māʾas</em> (to loathe, despise, reject) applied to his own life (<em>ḥayyê</em>) is Job's most direct expression of self-rejection. The phrase <em>lōʾ lěʿōlām ʾeḥyeh</em> (I will not live forever) is a remarkable anti-immortality claim: Job does not want eternal life in this condition; he wants it to end. <em>Heḇel yāmāy</em> (my days are vanity/breath) echoes Ecclesiastes' opening (<em>hevel havalim</em>) but in Job's mouth it is not philosophical observation but experiential cry. The command <em>ḥăḏal mimmennî</em> (cease from me, leave me alone) is addressed to God: it is simultaneously a prayer (addressed to God) and a desire for divine absence (leave me).</p>",
    "17": "<p><strong>māh-ʾěnôš kî-tǝḡaddəlennû wəkî-ṯāśîm ʾēlāyw libbəḵā</strong>: 'What is man, that you make so much of him, and that you set your heart on him?' This is the deliberate inversion of Psalm 8:4: 'What is man that you are mindful of him, and the son of man that you care for him?' (Ps 8:4). The lexical parallels are exact: <em>māh-ʾěnôš</em> (what is man), <em>tāśîm... libbəḵā</em> (set your heart on him = God's attention). But Psalm 8's awe at divine condescension in blessing humanity becomes in Job 7 horror at divine condescension in tormenting humanity. The same act of divine attention — infinitely great God noticing infinitely small man — is experienced as honor in Psalm 8 and as persecution in Job 7. Both are honest responses; the NT resolves the tension in the incarnation: God became man (divine condescension as honor) and suffered (divine condescension as solidarity with Job's terror).</p>",
    "18": "<p><strong>wattip̄qəḏennû liḇqārîm lirəgāʿîm tiḇḥānennu</strong>: 'visit him every morning and test him every moment?' The divine verbs continue: <em>pāqaḏ</em> (to visit, attend to — in both gracious and punitive senses) and <em>bāḥan</em> (to test, examine, assay — as metal is tested in fire, cf. Ps 17:3; 26:2; Prov 17:3; Zech 13:9). In the Psalms, both verbs can be positive: 'You have tested my heart, you have visited me by night' (Ps 17:3) in the context of divine vindication. Here, God's morning visitation (<em>liḇqārîm</em>) and moment-by-moment testing (<em>lirəgāʿîm</em>) are experienced not as divine care but as surveillance and torment. The complaint is that the divine attention appropriate to a covenant examination is being applied continuously without relief — every morning and every moment.</p>",
    "19": "<p><strong>kammāh lōʾ-ṯišʿeh mimmennî lōʾ-ṯarp̄ennî ʿaḏ-bəlōʿî ṯūqqî</strong>: 'How long will you not look away from me, nor leave me alone till I swallow my spit?' The verb <em>šāʿāh</em> (to look away, to avert the gaze) inverts the standard prayer for divine attention: Job prays for divine inattention as relief. <em>Rāp̄āh</em> (to let go, leave alone — the same root as 'be still and know that I am God,' Ps 46:10) is the request to cease the divine grip. The hyperbole of 'till I swallow my spit' (literally: till my swallowing of my spittle, a proverbial expression for the briefest possible moment) expresses the desperation: Job cannot get even the most minimal pause in divine attention/assault.</p>",
    "20": "<p><strong>ḥāṭāʾṯî māh ʾep̄ʿal lāḵ nōṣēr hāʾāḏām lāmmāh śamtanî ləmiḏʾākekā waʾehyeh ʿālay māśāʾ</strong>: 'If I sin, what do I do to you, you watcher of mankind? Why have you made me your mark? Why have I become a burden to you?' Three devastating questions. First: <em>ḥāṭāʾṯî māh ʾep̄ʿal lāḵ</em> (if I have sinned, what have I done to you?) — a theodicy question about whether human sin actually damages God, implying that divine punishment may be disproportionate to any actual harm done. Second: <em>nōṣēr hāʾāḏām</em> (watcher/guardian of man — <em>nōṣēr</em> is used for watchers both benign, Ps 121:4, and hostile) — addressed directly to God as the one who surveils all human action. Third: <em>śamtanî ləmiḏʾākekā</em> (you have made me your mark/target — <em>mip̄gāʿ</em> or <em>miḏʾāh</em>, the target of an archer) — God is the archer (cf. 6:4: arrows of the Almighty) and Job is the target. The lament is not atheism but the most intense form of theism: Job is speaking precisely to the God he believes is doing this.</p>",
    "21": "<p><strong>wəlāmmāh lōʾ-ṯiśśāʾ pišʿî wəṯaʿăḇîr ʾet-ʿăwōnî kî-ʿattāh ləʿāp̄ār ʾeškāḇ ûšiḥăraṯanî wəʾênennî</strong>: 'Why do you not pardon my transgression and take away my iniquity? For now I shall lie in the earth; you will seek me, but I shall not be.' The final plea of the chapter pivots from complaint to petition: <em>nāśāʾ p̄išaʿ</em> (to lift, carry, forgive transgression — the standard forgiveness formula, Exod 34:7; Num 14:18; Ps 32:1, 5; 85:2) and <em>ʿāḇar ʿāwōn</em> (to pass over iniquity — used by Moses in Exod 34:7 and by Micah 7:18: 'Who is a God like you, pardoning iniquity and passing over transgression?'). Job is not confessing specific sin but using the full forgiveness vocabulary as a plea for divine release: if there is any sin, forgive it — before the opportunity is gone. The closing line is Job's ultimate forensic weapon: <em>ûšiḥăraṯanî wəʾênennî</em> (you will seek me, but I shall not be). When Job is dead, God will have lost his witness, his case, his defendant. The urgency of the divine response is framed as equally urgent for God's justice as for Job's — a remarkable theological claim that prefigures the NT's account of God's own stake in human redemption.</p>"
  }
}

def main():
    d = load_comm('mkt-original', 'job')
    before = sum(len(v) for v in d.values())
    merge_comm(d, JOB_ORIGINAL_5_7)
    after = sum(len(v) for v in d.values())
    save_comm('mkt-original', 'job', d)
    for ch in ['5', '6', '7']:
        vs = sorted(d.get(ch, {}).keys(), key=int)
        print(f'  ch{ch}: {len(vs)} verses')
    print(f'wrote {after - before} new verses ({after} total)')

if __name__ == '__main__':
    main()
